import {Card} from "../../../entities/card";
import {useSelector} from "react-redux";
import {selectCardsByModuleIds} from "../../../entities/training";
import {uniqueAndShuffle} from "../../../shared/utils/uniqueAndShuffle";
import {use, useEffect, useState} from "react";
import {TrainingCard, TrainingPayload} from "../../../shared/types/trainingPayload";
import {completeTraining} from "../../../shared/api/trainApi";

export function useTraining(typeTraining: string, moduleIds: number[]) {
    const rawCards = useSelector(selectCardsByModuleIds(moduleIds));
    const cards = rawCards.filter((card): card is Card => card !== undefined);

    const [isOpenModal, setIsOpenModal] = useState(false);
    const [index, setIndex] = useState<number>(0);
    const [helper, setHelper] = useState(false);
    const [results, setResults] = useState<TrainingPayload | null>(null);
    const [trainingCards, setTrainingCards] = useState<TrainingCard[]>([]);
    const startDate = useState(() => Date.now())[0];

    const currentCard = cards[index];

    const recordAnswer = (card: Card, correct: boolean) => {
        setTrainingCards(prev => {
            const updated = [...prev, { card, correct }];

            const isLastCard = index >= cards.length - 1;

            if (isLastCard) {
                finishTraining(updated);
            } else {
                setIndex(i => i + 1);
            }

            return updated;
        });
    };

    const finishTraining = (finalCards: TrainingCard[]) => {
        const finishResults: TrainingPayload = {
            typeTraining,
            moduleIds,
            cards: finalCards,
            duration: Math.round((Date.now() - startDate) / 1000),
            date: new Date().toISOString(),
        };

        completeTraining(finishResults);
        setResults(finishResults);
        setIsOpenModal(true);
    };

    return {
        cards,
        currentCard,
        index,
        helper,
        setHelper,
        isOpenModal,
        results,
        recordAnswer,
    };
}
